messages.content:
Extract data from the following document based on the JSON schema.
Return null if the document does not contain information relevant to schema.
Return only the JSON with no explanation text.
The JSON schema is as follows:
{
  "type": "object",
  "required": [
    "accountNumber",
    "period",
    "transactions",
    "totalWithdrawals",
    "totalDeposits",
    "total"
  ],
  "properties": {
    "total": {
      "type": "number",
      "description": "Net total (deposits minus withdrawals) for the period"
    },
    "period": {
      "type": "object",
      "required": [
        "start",
        "end"
      ],
      "properties": {
        "end": {
          "type": "string",
          "description": "End date of the statement period exactly as it appears"
        },
        "start": {
          "type": "string",
          "description": "Start date of the statement period exactly as it appears"
        }
      },
      "description": "Date range for the account statement period"
    },
    "transactions": {
      "type": "array",
      "items": {
        "type": "object",
        "required": [
          "date",
          "description",
          "deposit",
          "withdrawal",
          "total"
        ],
        "properties": {
          "date": {
            "type": "string",
            "description": "Date of the transaction exactly as it appears"
          },
          "total": {
            "type": "number",
            "description": "Net balance after applying the deposit and withdrawal"
          },
          "deposit": {
            "type": "number",
            "description": "Amount deposited into the account"
          },
          "withdrawal": {
            "type": "number",
            "description": "Amount withdrawn from the account"
          },
          "description": {
            "type": "string",
            "description": "Description for the transaction"
          }
        }
      }
    },
    "accountNumber": {
      "type": "string",
      "description": "Unique identifier for the account"
    },
    "totalDeposits": {
      "type": "number",
      "description": "Total amount of deposits during the period"
    },
    "totalWithdrawals": {
      "type": "number",
      "description": "Total amount of withdrawals during the period"
    }
  }
}
